from flask import Flask, jsonify
from pymemcache.client import base
import time
import random

app = Flask(__name__)
cache = base.Client(('localhost', 11211))

def get_db_data():
    time.sleep(2)  # Simulate slow database query
    return {"data": random.randint(1, 100)}

@app.route('/cached/dbdata')
def cached_db_data():
    cache_key = 'db_data'
    response = cache.get(cache_key)
    if response is None:
        response = get_db_data()
        cache.set(cache_key, str(response), expire=60)  # Cache for 60 seconds
    else:
        response = eval(response.decode('utf-8'))
    return jsonify(response)

@app.route('/api')
def api_endpoint():
    cache_key = 'api_response'
    response = cache.get(cache_key)
    if response is None:
        response = {"message": "Hello, World!", "timestamp": time.time()}
        cache.set(cache_key, str(response), expire=30)  # Cache for 30 seconds
    else:
        response = eval(response.decode('utf-8'))
    return jsonify(response)

if __name__ == '__main__':
    app.run(debug=True)